import{_ as a,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Dimensionamiento de Cables","description":"","frontmatter":{},"headers":[],"relativePath":"es/cables/design/cable-sizing.md","filePath":"es/cables/design/cable-sizing.md"}'),l={name:"es/cables/design/cable-sizing.md"};function n(c,e,s,t,d,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="dimensionamiento-de-cables" tabindex="-1">Dimensionamiento de Cables <a class="header-anchor" href="#dimensionamiento-de-cables" aria-label="Permalink to &quot;Dimensionamiento de Cables&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción General <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción General&quot;">​</a></h2><p>El dimensionamiento de cables es el proceso de seleccionar el tamaño adecuado del conductor para transportar corriente eléctrica de forma segura y eficiente en una aplicación determinada.</p><p>Es una etapa crítica en el diseño eléctrico, ya que impacta directamente en el desempeño, la seguridad y el costo del sistema. Un dimensionamiento adecuado garantiza que el conductor pueda soportar la carga sin sobrecalentarse, manteniendo niveles de voltaje aceptables en el equipo.</p><hr><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El objetivo del dimensionamiento de cables es:</p><ul><li>Garantizar una operación segura evitando sobrecalentamiento</li><li>Mantener el voltaje dentro de límites aceptables</li><li>Asegurar un desempeño confiable del equipo</li><li>Cumplir con las normas eléctricas aplicables</li></ul><p>Un dimensionamiento incorrecto puede provocar fallas en equipos, reducción de vida útil o fallos del sistema.</p><hr><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>El dimensionamiento de cables se basa en evaluar múltiples factores y seleccionar un conductor que cumpla con todos simultáneamente.</p><p>Los criterios principales son:</p><ol><li><p><strong>Capacidad de corriente (ampacidad)</strong><br> El cable debe transportar la corriente esperada sin exceder los límites de temperatura.</p></li><li><p><strong>Caída de voltaje</strong><br> El cable debe mantener el voltaje dentro de límites aceptables en la carga.</p></li><li><p><strong>Condiciones de instalación</strong><br> La disipación de calor depende de cómo y dónde se instala el cable.</p></li><li><p><strong>Coordinación de protecciones</strong><br> El cable debe ser compatible con los dispositivos de protección (interruptores, fusibles).</p></li></ol><p>El tamaño seleccionado debe cumplir con la condición más restrictiva de estos criterios.</p><hr><h2 id="proceso-basico-de-dimensionamiento" tabindex="-1">Proceso Básico de Dimensionamiento <a class="header-anchor" href="#proceso-basico-de-dimensionamiento" aria-label="Permalink to &quot;Proceso Básico de Dimensionamiento&quot;">​</a></h2><h3 id="_1-determinar-la-corriente-de-carga" tabindex="-1">1. Determinar la Corriente de Carga <a class="header-anchor" href="#_1-determinar-la-corriente-de-carga" aria-label="Permalink to &quot;1. Determinar la Corriente de Carga&quot;">​</a></h3><p>Identificar la corriente a plena carga (FLC) del equipo.</p><ul><li>A partir de la placa de datos</li><li>De normas o tablas de referencia</li></ul><hr><h3 id="_2-aplicar-factores-de-diseno" tabindex="-1">2. Aplicar Factores de Diseño <a class="header-anchor" href="#_2-aplicar-factores-de-diseno" aria-label="Permalink to &quot;2. Aplicar Factores de Diseño&quot;">​</a></h3><p>Ajustar la corriente según los requisitos del sistema.</p><p>Ejemplos:</p><ul><li>Cargas continuas (frecuentemente requieren un margen, como 125%)</li><li>Factores de seguridad definidos por normas</li></ul><hr><h3 id="_3-seleccionar-un-tamano-inicial-de-conductor" tabindex="-1">3. Seleccionar un Tamaño Inicial de Conductor <a class="header-anchor" href="#_3-seleccionar-un-tamano-inicial-de-conductor" aria-label="Permalink to &quot;3. Seleccionar un Tamaño Inicial de Conductor&quot;">​</a></h3><p>Elegir un tamaño de conductor que cumpla o supere la corriente ajustada usando tablas de ampacidad.</p><hr><h3 id="_4-verificar-la-caida-de-voltaje" tabindex="-1">4. Verificar la Caída de Voltaje <a class="header-anchor" href="#_4-verificar-la-caida-de-voltaje" aria-label="Permalink to &quot;4. Verificar la Caída de Voltaje&quot;">​</a></h3><p>Evaluar si el cable mantiene un voltaje aceptable en la carga.</p><ul><li>Si la caída de voltaje es demasiado alta → aumentar el tamaño del conductor</li></ul><hr><h3 id="_5-aplicar-factores-de-correccion" tabindex="-1">5. Aplicar Factores de Corrección <a class="header-anchor" href="#_5-aplicar-factores-de-correccion" aria-label="Permalink to &quot;5. Aplicar Factores de Corrección&quot;">​</a></h3><p>Ajustar según condiciones reales de instalación:</p><ul><li>Temperatura ambiente</li><li>Agrupamiento de cables</li><li>Método de instalación (tubería, charola, aire)</li></ul><p>Si la desclasificación reduce la corriente permitida por debajo de la requerida, se debe aumentar el tamaño del conductor.</p><hr><h3 id="_6-verificar-compatibilidad-con-protecciones" tabindex="-1">6. Verificar Compatibilidad con Protecciones <a class="header-anchor" href="#_6-verificar-compatibilidad-con-protecciones" aria-label="Permalink to &quot;6. Verificar Compatibilidad con Protecciones&quot;">​</a></h3><p>Asegurar que el cable esté correctamente protegido por dispositivos contra sobrecorriente y que soporte condiciones de falla.</p><hr><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>El dimensionamiento de cables se utiliza en:</p><ul><li>Instalaciones de motores</li><li>Sistemas de distribución eléctrica</li><li>Diseño de tableros de control</li><li>Conexión de equipos industriales</li><li>Diseño de infraestructura y plantas</li></ul><hr><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><p>Al dimensionar cables:</p><ul><li>Considerar siempre condiciones reales de operación, no ideales</li><li>Evaluar tanto la ampacidad como la caída de voltaje</li><li>Aplicar todos los factores de corrección relevantes</li><li>Utilizar normas aplicables (NEC, IEC) como guía</li><li>Considerar expansiones futuras o incrementos de carga</li></ul><hr><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>El dimensionamiento de cables suele ser iterativo; es común hacer ajustes después de evaluar todos los factores.</li><li>El cable más pequeño que cumple todos los criterios suele ser la opción más rentable.</li><li>La caída de voltaje se vuelve un factor dominante en recorridos largos.</li><li>Ignorar las condiciones de instalación es un error común.</li><li>En sistemas industriales, un dimensionamiento conservador mejora la confiabilidad, pero incrementa el costo.</li></ul>',51)])])}const b=a(l,[["render",n]]);export{m as __pageData,b as default};
